mapper.select:
SELECT COUNT(*) as count, COALESCE(SUM(COALESCE(contract_amount, order_amount, 0)), 0) as amount FROM gh_order WHERE del_flag = 0
AND create_time >= #{startTime}
AND create_time <= #{endTime}

SELECT
    SUM(CASE WHEN create_time >= #{todayStart} AND create_time <= #{todayEnd} THEN 1 ELSE 0 END) AS todayOrders,
    COALESCE(SUM(CASE WHEN create_time >= #{todayStart} AND create_time <= #{todayEnd}
        THEN COALESCE(contract_amount, order_amount, 0) ELSE 0 END), 0) AS todayAmount,
    SUM(CASE WHEN create_time >= #{monthStart} AND create_time <= #{monthEnd} THEN 1 ELSE 0 END) AS monthOrders,
    COALESCE(SUM(CASE WHEN create_time >= #{monthStart} AND create_time <= #{monthEnd}
        THEN COALESCE(contract_amount, order_amount, 0) ELSE 0 END), 0) AS monthAmount,
    SUM(CASE WHEN create_time >= #{yearStart} AND create_time <= #{yearEnd} THEN 1 ELSE 0 END) AS yearOrders,
    COALESCE(SUM(CASE WHEN create_time >= #{yearStart} AND create_time <= #{yearEnd}
        THEN COALESCE(contract_amount, order_amount, 0) ELSE 0 END), 0) AS yearAmount
FROM gh_order
WHERE del_flag = 0
  AND create_time >= #{yearStart}
  AND create_time <= #{yearEnd}

SELECT COALESCE(business_type, '其他') as businessType, COUNT(*) as count, COALESCE(SUM(COALESCE(contract_amount, order_amount, 0)), 0) as amount FROM gh_order WHERE del_flag = 0
AND create_time >= #{startTime}
AND create_time <= #{endTime}
GROUP BY business_type ORDER BY count DESC

SELECT COALESCE(salesman, '未分配') as salesman, COUNT(*) as orders, COALESCE(SUM(COALESCE(contract_amount, order_amount, 0)), 0) as amount FROM gh_order WHERE del_flag = 0
AND create_time >= #{startTime}
AND create_time <= #{endTime}
GROUP BY salesman ORDER BY orders DESC LIMIT #{limit}
